const elasticsearch = require('elasticsearch');

// Initialize ES client
const client = new elasticsearch.Client({
  host: 'localhost:9200',
  log: 'trace'
});

async function search(query) {
  const { body } = await client.search({
    index: 'your_index_name', // replace with your index name
    body: {
      query: {
        bool: {
          must: []
        }
      },
      script_score: {
        script: new elasticsearch.Script({
          source: query.script, // user-provided custom scoring script
          params: {} // parameters for the script, if any
        })
      }
    }
  });

  if (query.filters) {
    body.body.query.bool.must = body.body.query.bool.must.concat(query.filters);
  }

  return body;
}

// Example usage:
